<?php declare(strict_types=1);require_once dirname(__DIR__,2).'/includes/auth.php';require_once dirname(__DIR__,2).'/includes/conexion.php';exigirRol(['usuario']);$q=obtenerConexion()->prepare('SELECT * FROM pedidos WHERE usuario_id=:u ORDER BY created_at DESC');$q->execute(['u'=>$_SESSION['usuario_id']]);$pedidos=$q->fetchAll();?><!doctype html><html lang="es"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Mis pedidos | Atenea</title><link rel="stylesheet" href="<?=atenea_url('src/estudiantes/assets/css/core/libs.min.css')?>"><link rel="stylesheet" href="<?=atenea_url('src/estudiantes/assets/css/hope-ui.min.css')?>"></head><body><main class="container py-5"><a class="btn btn-outline-primary mb-3" href="<?=atenea_url('src/estudiantes/index.php')?>">Volver al portal</a><div class="card"><div class="card-body"><h1 class="h3">Mis pedidos</h1><div class="table-responsive"><table class="table"><thead><tr><th>Pedido</th><th>Fecha</th><th>Total</th><th>Estado</th></tr></thead><tbody><?php foreach($pedidos as$p):?><tr><td><?=atenea_e($p['numero'])?></td><td><?=date('d/m/Y H:i',strtotime($p['created_at']))?></td><td>$<?=number_format((float)$p['total'],2)?> <?=strtoupper($p['moneda'])?></td><td><span class="badge bg-primary"><?=atenea_e($p['estado'])?></span></td></tr><?php endforeach;?><?php if(!$pedidos):?><tr><td colspan="4" class="text-center">Aún no tienes pedidos.</td></tr><?php endif;?></tbody></table></div></div></div></main></body></html>
